// HTTP POST with Authentication
// Generated by: /k6.plan scenario=load target=https://httpbin.org/post sla=p95<500ms
// Updated: Uses environment variables for URL and authentication token
// Usage: k6 run --env BASE_URL=https://httpbin.org --env API_TOKEN=your_token post-with-auth.js

import http from 'k6/http';
import { check, sleep } from 'k6';

const baseUrl = __ENV.BASE_URL || 'https://httpbin.org';
const apiToken = __ENV.API_TOKEN || 'default-test-token';

export const options = {
  stages: [
    { duration: '2m', target: 30 },
    { duration: '5m', target: 30 },
    { duration: '2m', target: 0 },
  ],
  thresholds: {
    'http_req_duration': ['p(95)<500'],
    'http_req_failed': ['rate<0.01'],
    'checks': ['rate>0.95'],
  },
};

export default function postWithAuthScenario() {
  const payload = JSON.stringify({
    product_id: 'prod_123',
    quantity: 2,
    customer_id: `user_${__VU}`,
    timestamp: new Date().toISOString(),
  });

  const params = {
    headers: {
      'Content-Type': 'application/json',
      'Authorization': `Bearer ${apiToken}`,
    },
    tags: { name: 'create-order' },
    timeout: '30s',
  };

  const response = http.post(`${baseUrl}/post`, payload, params);

  check(response, {
    'status is 200': (r) => r.status === 200,
    'data echoed back': (r) => r.json('json.product_id') === 'prod_123',
    'response time < 500ms': (r) => r.timings.duration < 500,
  });

  sleep(1);
}
